  const orb      = pdoc.getElementById(`${ID}-orb`);
  const head     = pdoc.getElementById(`${ID}-head`);
  const btnClose = pdoc.getElementById(`${ID}-close`);
  const menu     = pdoc.getElementById(`${ID}-menu`);
  const shell    = pdoc.getElementById(`${ID}-shell`);
  const foxBtn   = pdoc.getElementById(`${ID}-fox-btn`);
  let isOpen = false;

  if (foxBtn) {
    foxBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      toastr.info('模块挂载成功，双人成行 V3.0 难逢北', '💬 ᴘʀɪsᴍ//ғᴏx');
    });
  }

  // ── Tavern Helper 核心控制函数 ──
  function isPromptEnabled(li) { return !li.classList.contains('completion_prompt_manager_prompt_disabled'); }
  function clickToggle(li) { const btn = li.querySelector('.prompt-manager-toggle-action'); if (btn) btn.click(); }

  // 核心匹配：严格根据名称去匹配
  function findByKeyword(keyword) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).filter(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      return name.trim() === keyword.trim();
    });
  }

  function ensureOn(keyword) { findByKeyword(keyword).forEach(li => { if (!isPromptEnabled(li)) clickToggle(li); }); }
  function ensureOff(keyword) { findByKeyword(keyword).forEach(li => { if (isPromptEnabled(li)) clickToggle(li); }); }

  // ── 模型组管理 (4 种模式核心缝合) ──
  const modelConfigs = {
    gemini: ['✨ Gemini', '✨Gemini✨', '—\\✨思考模式（简）'], 
    glm:    ['✨ Gemini', '✨Gemini✨', '—\\✨思考模式（简）'], 
    claude: ['🎨 Claude', '🎨Claude🎨', '—\\🎐思考模式'],
    c45s:   ['✨ Gemini', '🎨Claude🎨', '—\\🎐思考模式']
  };

  const allModelKws = [
    '✨ Gemini', '✨Gemini✨', '—\\✨思考模式（简）', '—\\✨思考模式（繁）', '—\\✨思考模式',
    '🎨 Claude', '🎨Claude🎨', '—\\🎐思考模式'
  ];

  function setModel(type) {
    if (!pdoc.querySelector('#completion_prompt_manager_list')) { toastr.warning('请先打开预设面板'); return; }

    const targetKws = modelConfigs[type] || [];

    // 自定义逻辑：如果是切Gemini或GLM，且当前已经开了繁版，就不强行关繁版开简版
    let preserveFan = false;
    if ((type === 'gemini' || type === 'glm') && isKeywordOn('—\\✨思考模式（繁）')) {
        preserveFan = true;
    }

    allModelKws.forEach(kw => {
      if (targetKws.includes(kw)) {
          if (preserveFan && kw === '—\\✨思考模式（简）') {
              // 繁版既然开着，就不开简版了
              ensureOff(kw);
          } else {
              ensureOn(kw);
          }
      } else {
          if (preserveFan && kw === '—\\✨思考模式（繁）') {
              ensureOn(kw); // 保持开启
          } else {
              ensureOff(kw);
          }
      }
    });

    const ids = { gemini: `${ID}-cot-gemini`, glm: `${ID}-cot-glm`, claude: `${ID}-cot-claude`, c45s: `${ID}-cot-c45s` };
    Object.values(ids).forEach(id => pdoc.getElementById(id)?.classList.remove('is-on'));
    pdoc.getElementById(ids[type])?.classList.add('is-on');

    toastr.success(`已切换模型模式: ${type.toUpperCase()}`);
  }

  pdoc.getElementById(`${ID}-cot-gemini`)?.addEventListener('click', () => setModel('gemini'));
  pdoc.getElementById(`${ID}-cot-glm`)?.addEventListener('click', () => setModel('glm'));
  pdoc.getElementById(`${ID}-cot-claude`)?.addEventListener('click', () => setModel('claude'));
  pdoc.getElementById(`${ID}-cot-c45s`)?.addEventListener('click', () => setModel('c45s'));

  // ── 主题切换逻辑 ──
  pdoc.querySelectorAll('.t-dot').forEach(dot => {
    dot.addEventListener('click', (e) => {
      e.stopPropagation();
      const theme = dot.getAttribute('data-theme');
      shell.className = `menu-shell ${theme}`;
      pdoc.querySelectorAll('.t-dot').forEach(d => d.classList.remove('active'));
      dot.classList.add('active');
      currentTheme = theme;
      savePos();
    });
  });

  // ── 单选及开关核心逻辑 (解耦排版，基于 data-group) ──
  pdoc.querySelectorAll('.toggle-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      if (!pdoc.querySelector('#completion_prompt_manager_list')) { toastr.warning('请先打开预设面板'); return; }

      const kw = btn.getAttribute('data-kw');
      const groupName = btn.getAttribute('data-group');
      const isOn = btn.classList.contains('is-on');

      if (isOn) {
        ensureOff(kw);
        btn.classList.remove('is-on');
        if (kw === '加强世界书阅读') ensureOff('🔗世界书CoT');
      } else {
        // 如果存在分组 (互斥单选)
        if (groupName) {
          pdoc.querySelectorAll(`.toggle-btn[data-group="${groupName}"]`).forEach(otherBtn => {
            if (otherBtn !== btn) {
              ensureOff(otherBtn.getAttribute('data-kw'));
              otherBtn.classList.remove('is-on');
            }
          });

          // 对线模式切换对应的底层模型
          if (groupName === 'ai-chat') {
            if (kw === '🤬AI对话（对线哈基米）') setModel('gemini');
            else if (kw === '👊拷打（拷打克劳德）') setModel('claude');
          }
        }

        ensureOn(kw);
        btn.classList.add('is-on');
        if (kw === '加强世界书阅读') ensureOn('🔗世界书CoT');
      }
    });
  });

  // ── 初始化状态检测 ──
  function isKeywordOn(keyword) {
    const items = findByKeyword(keyword);
    return items.length > 0 && items.every(li => isPromptEnabled(li));
  }

  function initDetectState() {
    if (!pdoc.querySelector('#completion_prompt_manager_list')) return;

    // 模型状态检测
    const hasGemCoT = isKeywordOn('—\\✨思考模式（简）') || isKeywordOn('—\\✨思考模式（繁）') || isKeywordOn('—\\✨思考模式');
    const hasClaudeCoT = isKeywordOn('—\\🎐思考模式');
    const hasGemEnd = isKeywordOn('✨ Gemini') || isKeywordOn('✨Gemini✨');
    const hasClaudeEnd = isKeywordOn('🎨 Claude') || isKeywordOn('🎨Claude🎨');

    let currentModel = null;
    if (hasClaudeCoT && hasGemEnd) currentModel = 'c45s';
    else if (hasClaudeCoT && hasClaudeEnd) currentModel = 'claude';
    else if (hasGemCoT) currentModel = 'gemini'; // GLM同理, 优先显示gemini

    if (currentModel) {
      const ids = { gemini: `${ID}-cot-gemini`, glm: `${ID}-cot-glm`, claude: `${ID}-cot-claude`, c45s: `${ID}-cot-c45s` };
      Object.values(ids).forEach(id => pdoc.getElementById(id)?.classList.remove('is-on')); // clear first
      pdoc.getElementById(ids[currentModel])?.classList.add('is-on');
    }

    // 常规按钮检测
    pdoc.querySelectorAll('.toggle-btn').forEach(btn => {
      btn.classList.toggle('is-on', isKeywordOn(btn.getAttribute('data-kw')));
    });
  }

  let initDone = false;
  function tryInitDetect() {
    if (initDone) return;
    if (pdoc.querySelector('#completion_prompt_manager_list')) { initDone = true; initDetectState(); }
  }
  setTimeout(tryInitDetect, 1200);
  setTimeout(tryInitDetect, 2500);

  // ── UI 位置展开逻辑 ──
  function updateMenuDirection() {
    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const menuH = 480; 
    if (orbX < pwin.innerWidth / 2) { menu.style.left = '0'; menu.style.right = 'auto'; } 
    else { menu.style.left = 'auto'; menu.style.right = '0'; }
    const spaceBelow = pwin.innerHeight - orbY - 60;
    if (spaceBelow < menuH && orbY > menuH / 2) {
      menu.style.top = 'auto'; menu.style.bottom = '52px'; root.classList.add('open-up');
      menu.style.transformOrigin = orbX < pwin.innerWidth / 2 ? 'bottom left' : 'bottom right';
    } else {
      menu.style.top = '52px'; menu.style.bottom = 'auto'; root.classList.remove('open-up');
      menu.style.transformOrigin = orbX < pwin.innerWidth / 2 ? 'top left' : 'top right';
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) { updateMenuDirection(); initDetectState(); } 
    else { root.classList.remove('open-up'); }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }

  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  function savePos() {
    try { insertOrAssignVariables({ orbV5_prismfox_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top), theme: currentTheme }) }, { type: 'global' }); } catch (_) {}
  }

  let drag = false, ox = 0, oy = 0, moved = false, dragMask = null;
  function createMask() {
    dragMask = parent.document.createElement('div');
    dragMask.style.cssText = 'position:fixed;inset:0;z-index:2147483646;cursor:grabbing;background:transparent;';
    parent.document.body.appendChild(dragMask);
  }
  function removeMask() { dragMask?.remove(); dragMask = null; }
  function startDrag(cx, cy) {
    drag = true; moved = false; const rect = root.getBoundingClientRect(); ox = cx - rect.left; oy = cy - rect.top;
    root.style.transition = 'none'; createMask();
  }
  function moveDrag(cx, cy) {
    if (!drag) return; moved = true;
    root.style.left = Math.max(4, Math.min(cx - ox, pwin.innerWidth  - 50)) + 'px';
    root.style.top  = Math.max(4, Math.min(cy - oy, pwin.innerHeight - 50)) + 'px';
  }
  function endDrag() {
    if (!drag) return; drag = false; root.style.transition = ''; removeMask();
    if (moved) savePos();
  }

  orb.addEventListener('mousedown', e => { startDrag(e.clientX, e.clientY); e.preventDefault(); });
  head.addEventListener('mousedown', e => { if (e.target.id === `${ID}-close` || e.target.classList.contains('t-dot')) return; startDrag(e.clientX, e.clientY); e.preventDefault(); });
  parent.document.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
  parent.document.addEventListener('mouseup', () => endDrag());

  orb.addEventListener('click', () => { if (moved) { moved = false; return; } toggle(); });

  orb.addEventListener('touchstart', e => { startDrag(e.touches[0].clientX, e.touches[0].clientY); e.stopPropagation(); }, { passive: true });
  orb.addEventListener('touchmove', e => { if (!drag) return; moveDrag(e.touches[0].clientX, e.touches[0].clientY); }, { passive: true });
  orb.addEventListener('touchend', e => { const wasMoved = moved; endDrag(); if (!wasMoved) toggle(); e.stopPropagation(); e.preventDefault(); }, { passive: false });

  head.addEventListener('touchstart', e => { if (e.target.id === `${ID}-close` || e.target.classList.contains('t-dot')) return; startDrag(e.touches[0].clientX, e.touches[0].clientY); e.stopPropagation(); }, { passive: true });
  head.addEventListener('touchmove', e => { if (!drag) return; moveDrag(e.touches[0].clientX, e.touches[0].clientY); }, { passive: true });
  head.addEventListener('touchend', e => { endDrag(); e.stopPropagation(); }, { passive: true });

  window.addEventListener('pagehide', () => { pdoc.getElementById(ID)?.remove(); pdoc.getElementById(`${ID}-style`)?.remove(); });
  window.addEventListener('unload', () => { pdoc.getElementById(ID)?.remove(); pdoc.getElementById(`${ID}-style`)?.remove(); });

}));

