    animation-delay: 0.1s;
}

.meow_FM_thought-box:nth-child(2) .meow_FM_thought-char {
    animation-delay: 0.2s;
}

.meow_FM_thought-box:nth-child(3) .meow_FM_thought-char {
    animation-delay: 0.3s;
}

.meow_FM_thought-box:nth-child(4) .meow_FM_thought-char {
    animation-delay: 0.4s;
}

.meow_FM_thought-box:nth-child(5) .meow_FM_thought-char {
    animation-delay: 0.5s;
}

.meow_FM_thought-box:nth-child(6) .meow_FM_thought-char {
    animation-delay: 0.6s;
}

.meow_FM_thought-box:nth-child(7) .meow_FM_thought-dot,
.meow_FM_thought-box:nth-child(7) .meow_FM_thought-char {
    animation-delay: 0.7s;
}

